// ======================================================
// 1. FONTE A — DICIONÁRIO DO BANCO (INPUT DO NODE)
// ======================================================
const referenceData = $input.all().map(i => i.json);

const FIELD_ALIASES = {
  email: ["email", "e-mail", "mail"],
  company: ["empresa", "organizacao", "organização", "companhia"],
  position: ["cargo", "profissao", "profissão", "funcao", "função", "ocupacao"],
  birth_date: ["data de nascimento", "nascimento", "aniversario", "aniversário", "data nascimento"],
  cpf: ["cpf", "documento", "cpf/cnpj"],
  assistant_email: ["email do assistente", "email assistente", "assistente", "secretaria", "secretária"],
  cellphone: ["telefone fixo", "telefone", "fixo", "comercial", "fone"],
  linkedin: ["linkedin", "link linkedin", "perfil linkedin"],
  instagram: ["instagram", "insta", "perfil instagram"]
};


// ======================================================
// 2. FONTE B — DADOS DO TRIGGER
// ======================================================
let userData = null;

const possibleTriggerNodes = [
  'When Executed by Another Workflow',
  'Edit Fields',
  'Trigger',
  'Webhook',
  'Start'
];

for (const nodeName of possibleTriggerNodes) {
  try {
    const item = $(nodeName).first();
    if (item?.json?.Fields && item?.json?.Values) {
      userData = item.json;
      break;
    }
  } catch {}
}

if (!userData) {
  throw new Error("Não foi possível localizar Fields/Values no Trigger.");
}

// ======================================================
// 3. UTILITÁRIOS
// ======================================================
function normalize(str = "") {
  return str
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]/g, "");
}

function buildResult(ref, value, participantId, eventId) {
  return {
    participant_id: participantId,
    event_id: eventId,
    field_name: ref.field_name,
    field_id: ref.field_id,
    field_type: ref.field_type,
    value
  };
}

function resolveAlias(inputFieldNormalized) {
  for (const [canonicalField, aliases] of Object.entries(FIELD_ALIASES)) {
    if (aliases.map(normalize).includes(inputFieldNormalized)) {
      return canonicalField;
    }
  }
  return null;
}


// ======================================================
// 4. PROCESSAMENTO
// ======================================================
const fieldsList = userData.Fields;
const valuesList = userData.Values;
const participantId = userData.participant_id;
const eventId = userData.event_id;

const matchedFields = [];

for (let i = 0; i < fieldsList.length; i++) {
  const originalInput = fieldsList[i];
  const inputValue = valuesList[i] ?? null;

  const normalizedInput = normalize(originalInput);

  // 🔁 1️⃣ RESOLVE ALIAS (cargo → position, empresa → company, etc)
  const resolvedFieldName =
    resolveAlias(normalizedInput) || normalizedInput;

  let match =
    // 2️⃣ Match exato
    referenceData.find(ref =>
      ref.field_name &&
      normalize(ref.field_name) === resolvedFieldName
    ) ||

    // 3️⃣ Banco contém input
    referenceData.find(ref =>
      ref.field_name &&
      normalize(ref.field_name).includes(resolvedFieldName)
    ) ||

    // 4️⃣ Match semântico leve
    referenceData.find(ref => {
      if (!ref.field_name) return false;

      const refNorm = normalize(ref.field_name)
        .replace(/(de|do|da|das|dos)/g, "");

      return refNorm === resolvedFieldName;
    });

  if (!match) {
    throw new Error(`Campo não encontrado no dicionário: ${originalInput}`);
  }

  matchedFields.push({
    participant_id: participantId,
    event_id: eventId,
    field_name: match.field_name,
    field_id: match.field_id,
    field_type: match.field_type,
    value: inputValue,
    _original_input: originalInput
  });
}

// ======================================================
// 5. RETORNO FINAL
// ======================================================
return {
  json: {
    participant_id: participantId,
    event_id: eventId,
    fields: matchedFields
  }
};

const participant = items[0].json;

const REQUIRED_FIELDS = [
  { key: 'email', label: 'Email' },
  { key: 'empresa', label: 'Empresa' },
  { key: 'cargo', label: 'Cargo' },
  { key: 'data_nascimento', label: 'Data de Nascimento' },
  { key: 'cpf', label: 'CPF' },
  { key: 'email_assistente', label: 'Email do Assistente' },
  { key: 'telefone_fixo', label: 'Telefone Fixo' },
  { key: 'linkedin', label: 'LinkedIn' },
  { key: 'instagram', label: 'Instagram' }
];

const isCollected = (fieldKey) =>
  participant[`${fieldKey}_status`] === 'Coletado';

const listarCampos = (campos) =>
  campos.map(c => `• ${c.label}`).join('\n');

const obrigatoriosPendentes = REQUIRED_FIELDS.filter(
  f => !isCollected(f.key)
);

let acao = null;
let mensagem = '';

if (obrigatoriosPendentes.length > 0) {
  acao = 'SOLICITAR_DADOS_PENDENTES';
  mensagem =
`✅ Dados recebidos!

Para concluir sua inscrição, ainda precisamos de algumas informações:

${listarCampos(obrigatoriosPendentes)}

É só me enviar por aqui quando puder 😊`;
}
else {
  acao = 'ATUALIZAR_STATUS_PARTICIPANTE';
  mensagem =
`🎉 Inscrição concluída com sucesso!

Todos os dados foram coletados.

Seu status foi atualizado para *Inscrito*.

Qualquer coisa, é só me chamar 😊`;
}

return [
  {
    json: {
      participant_id: participant.id,
      acao,
      novo_status_participante:
        acao === 'ATUALIZAR_STATUS_PARTICIPANTE'
          ? 'inscrito'
          : null,
      campos_pendentes: obrigatoriosPendentes.map(f => f.key),
      mensagem
    }
  }
];
